backBtn:
{!isEditing && (
                <button 
                  onClick={() => {
                    setSelectedArticle(null);
                  }}
                  className="flex items-center space-x-2 text-sm font-bold text-[#243c5a] hover:text-orange-600 transition-colors mb-4 print:hidden"
                >
                  <span className="text-lg font-normal">←</span>
                  <span>Kembali ke daftar</span>
                </button>
              )}

canvasSheet:
) : (
                    <div className="flex items-center space-x-3 w-full justify-between sm:justify-end">
                      {/* Autosave badge status indicator */}
                      <span className="text-xs font-medium flex items-center text-slate-400">
                        {autosaveStatus === 'saving' && (
                          <span className="flex items-center">
                            <span className="h-2 w-2 rounded-full bg-amber-400 animate-ping mr-1.5"></span>
                            Menyimpan draf...
                          </span>
                        )}
                        {autosaveStatus === 'saved' && (
                          <span className="text-emerald-600 flex items-center">
                            <Check className="h-3.5 w-3.5 mr-1" />
                            Semua draf tersimpan
                          </span>
                        )}
                        {autosaveStatus === 'idle' && (
                          <span className="flex items-center text-slate-300">
                            <Save className="h-3.5 w-3.5 mr-1" />
                            Autosave Aktif
                          </span>
                        )}
                      </span>
                      <button
                        onClick={handleSaveAndClose}
                        className="bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-extrabold py-2 px-5 rounded-xl flex items-center space-x-1.5 transition-all shadow-md"
                      >
                        <Check className="h-3.5 w-3.5" />
                        <span>Selesai &amp; Simpan</span>
                      </button>
                    </div>
                  )}
                </div>
              </div>


              <div className="relative flex w-full">

                {/* --- EDITOR RIBBON TOOLBAR (LEFT SIDEBAR) --- */}
                {isEditing && (
                  <div className="formatting-ribbon fixed left-0 top-[64px] h-[calc(100vh-64px)] w-[280px] bg-white border-r border-slate-200 p-5 print:hidden z-40 overflow-y-auto flex flex-col gap-4 shadow-sm" id="editorRibbon">

                  {/* Contextual Tab Headers like Microsoft Office/Google Docs */}
                  {selectedImageElement && (
                    <div className="flex items-center justify-between border-b border-slate-100 pb-1.5 mb-2">
                      <div className="flex gap-2">
                        <button
                          type="button"
                          onClick={() => setActiveRibbonTab('text')}
                          className={`px-3 py-1 text-xs font-bold rounded-lg transition-all cursor-pointer ${activeRibbonTab === 'text' ? 'bg-indigo-50 text-indigo-600 shadow-2xs' : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'}`}
                        >
                          Beranda (Teks)
                        </button>
                        <button
                          type="button"
                          onClick={() => setActiveRibbonTab('image')}
                          className={`px-3 py-1 text-xs font-bold rounded-lg transition-all flex items-center gap-1.5 cursor-pointer ${activeRibbonTab === 'image' ? 'bg-amber-500 text-white shadow-2xs' : 'bg-amber-50/50 text-amber-700 hover:bg-amber-50'}`}
                        >
                          <ImageIcon className="h-3.5 w-3.5" />
                          <span>Format Gambar</span>
                        </button>
                      </div>
                      <span className="text-[10px] font-bold text-amber-600 bg-amber-50 px-2 py-0.5 rounded-full animate-pulse flex items-center gap-1">
                        <span className="w-1.5 h-1.5 rounded-full bg-amber-500"></span>
                        Alat Gambar Aktif
                      </span>
                    </div>
                  )}

                  {activeRibbonTab === 'image' && selectedImageElement ? (
                    /* --- IMAGE TOOLS COMPACT RIBBON TOOLBAR (MICROSOFT WORD STYLE) --- */
                    <div className="bg-slate-50 border border-slate-200 rounded-xl p-1.5 shadow-sm flex flex-col gap-3 overflow-y-auto max-h-[60vh] custom-scrollbar pr-1 select-none text-xs relative animate-in fade-in duration-200">

                      {/* 1. PENYESUAIAN (Adjust) */}
                      <div className="flex flex-col justify-between pr-2.5 border-b border-slate-200 pb-3 min-w-full h-auto">
                        <div className="flex flex-wrap items-center gap-1.5 h-auto">
                          {renderRibbonDropdown('brightness', 'Kecerahan', <Sliders className="h-4 w-4 text-indigo-600 shrink-0" />, (
                            <div className="space-y-2 w-[210px]">
                              <div className="flex justify-between items-center text-xs">
                                <span className="font-semibold text-slate-700">Kecerahan</span>
                                <span className="font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded text-[10px]">{imageBrightness}%</span>
                              </div>
                              <input
                                type="range"
                                min="50"
                                max="150"
                                value={imageBrightness}
                                onChange={(e) => updateSelectedImage({ brightness: parseInt(e.target.value) })}
                                className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                              />
                              <div className="flex justify-between text-[9px] text-slate-400 font-bold font-mono">
                                <span>50%</span>
                                <span>100%</span>
                                <span>150%</span>
                              </div>
                            </div>
                          ))}

                          {renderRibbonDropdown('contrast', 'Kontras', <Sliders className="h-4 w-4 text-indigo-600 shrink-0 rotate-90" />, (
                            <div className="space-y-2 w-[210px]">
                              <div className="flex justify-between items-center text-xs">
                                <span className="font-semibold text-slate-700">Kontras</span>
                                <span className="font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded text-[10px]">{imageContrast}%</span>
                              </div>
                              <input
                                type="range"
                                min="50"
                                max="150"
                                value={imageContrast}
                                onChange={(e) => updateSelectedImage({ contrast: parseInt(e.target.value) })}
                                className="w-full h-1 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                              />
                              <div className="flex justify-between text-[9px] text-slate-400 font-bold font-mono">
                                <span>50%</span>
                                <span>100%</span>
                                <span>150%</span>
                              </div>
                            </div>
                          ))}

                          {renderRibbonDropdown('recolor', 'Efek Warna', <Palette className="h-4 w-4 text-indigo-600 shrink-0" />, (
                            <div className="space-y-1 w-[200px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Pilih Filter Warna</span>
                              {[
                                { id: 'none', label: 'Warna Asli (Normal)' },
                                { id: 'grayscale', label: 'Hitam Putih (Grayscale)' },
                                { id: 'sepia', label: 'Sepia (Retro Klasik)' },
                                { id: 'invert', label: 'Negatif (Invert)' },
                                { id: 'hue-90', label: 'Biru / Hijau (Hue 90°)' },
                                { id: 'hue-180', label: 'Merah / Ungu (Hue 180°)' },
                              ].map((opt) => (
                                <button
                                  key={opt.id}
                                  type="button"
                                  onClick={() => {
                                    updateSelectedImage({ recolor: opt.id });
                                    setOpenImagePopover(null);
                                  }}
                                  className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between transition-all cursor-pointer ${imageRecolor === opt.id ? 'bg-indigo-50 text-indigo-600 font-semibold' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}`}
                                >
                                  <span>{opt.label}</span>
                                  {imageRecolor === opt.id && <Check className="h-3 w-3 text-indigo-600 shrink-0" />}
                                </button>
                              ))}
                            </div>
                          ))}
                        </div>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider text-left mt-2 leading-none select-none">Penyesuaian</span>
                      </div>

                      {/* 2. BINGKAI & SUDUT (Borders & Radius) */}
                      <div className="flex flex-col justify-between px-2.5 border-b border-slate-200 pb-3 min-w-full h-auto">
                        <div className="flex flex-wrap items-center gap-1.5 h-auto">
                          {renderRibbonDropdown('borderColor', 'Warna Bingkai', <Palette className="h-4 w-4 text-emerald-600 shrink-0" />, (
                            <div className="space-y-2.5 w-[220px] p-1">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1 flex items-center gap-1">Palet Warna Bingkai</span>
                              <div className="grid grid-cols-6 gap-1.5">
                                {[
                                  '#000000', '#ffffff', '#ef4444', '#f97316', '#f59e0b', '#10b981',
                                  '#06b6d4', '#3b82f6', '#6366f1', '#8b5cf6', '#ec4899', '#cbd5e1',
                                  '#94a3b8', '#64748b', '#475569', '#334155', '#1e293b', '#0f172a'
                                ].map((hex) => (
                                  <button
                                    key={hex}
                                    type="button"
                                    onClick={() => {
                                      updateSelectedImage({ borderColor: hex });
                                    }}
                                    className={`w-7 h-7 rounded-full border border-slate-200 transition-all cursor-pointer flex items-center justify-center relative hover:scale-110 shadow-3xs`}
                                    style={{ backgroundColor: hex }}
                                    title={hex}
                                  >
                                    {imageBorderColor.toLowerCase() === hex.toLowerCase() && (
                                      <span className={`w-2 h-2 rounded-full ${hex.toLowerCase() === '#ffffff' ? 'bg-black' : 'bg-white'}`}></span>
                                    )}
                                  </button>
                                ))}
                              </div>
                              <div className="pt-2 border-t border-slate-100 flex gap-2 items-center">
                                <span className="text-[10px] font-bold text-slate-400 uppercase">Kustom:</span>
                                <input
                                  type="color"
                                  value={imageBorderColor}
                                  onChange={(e) => updateSelectedImage({ borderColor: e.target.value })}
                                  className="w-8 h-6 border border-slate-200 rounded p-0 cursor-pointer"
                                />
                                <span className="text-[10px] font-semibold text-slate-600 font-mono">{imageBorderColor}</span>
                              </div>
                            </div>
                          ))}

                          {renderRibbonDropdown('borderWidth', 'Tebal', <Frame className="h-4 w-4 text-emerald-600 shrink-0" />, (
                            <div className="space-y-1 w-[180px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Tebal Bingkai</span>
                              {[
                                { id: '0px', label: 'Tanpa Bingkai (0px)' },
                                { id: '1px', label: 'Sangat Tipis (1px)' },
                                { id: '2px', label: 'Tipis (2px)' },
                                { id: '3px', label: 'Sedang (3px)' },
                                { id: '4px', label: 'Tebal (4px)' },
                                { id: '6px', label: 'Sangat Tebal (6px)' },
                              ].map((opt) => (
                                <button
                                  key={opt.id}
                                  type="button"
                                  onClick={() => {
                                    updateSelectedImage({ borderWidth: opt.id });
                                    setOpenImagePopover(null);
                                  }}
                                  className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between transition-all cursor-pointer ${imageBorderWidth === opt.id ? 'bg-emerald-50 text-emerald-700 font-semibold' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}`}
                                >
                                  <span>{opt.label}</span>
                                  {imageBorderWidth === opt.id && <Check className="h-3 w-3 text-emerald-600 shrink-0" />}
                                </button>
                              ))}
                            </div>
                          ))}

                          {renderRibbonDropdown('borderStyle', 'Gaya', <Frame className="h-4 w-4 text-emerald-600 shrink-0 rotate-45" />, (
                            <div className="space-y-1 w-[180px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Gaya Bingkai</span>
                              {[
                                { id: 'solid', label: 'Garis Lurus (Solid)' },
                                { id: 'dashed', label: 'Putus-Putus (Dashed)' },
                                { id: 'dotted', label: 'Titik-Titik (Dotted)' },
                                { id: 'double', label: 'Garis Ganda (Double)' },
                              ].map((opt) => (
                                <button
                                  key={opt.id}
                                  type="button"
                                  onClick={() => {
                                    updateSelectedImage({ borderStyle: opt.id });
                                    setOpenImagePopover(null);
                                  }}
                                  className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between transition-all cursor-pointer ${imageBorderStyle === opt.id ? 'bg-emerald-50 text-emerald-700 font-semibold' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}`}
                                >
                                  <span>{opt.label}</span>
                                  {imageBorderStyle === opt.id && <Check className="h-3 w-3 text-emerald-600 shrink-0" />}
                                </button>
                              ))}
                            </div>
                          ))}

                          {renderRibbonDropdown('borderRadius', 'Sudut Bulat', <Crop className="h-4 w-4 text-emerald-600 shrink-0" />, (
                            <div className="space-y-1 w-[200px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Kelengkungan Sudut</span>
                              {[
                                { id: 'rounded-none', label: 'Tajam / Siku (0px)' },
                                { id: 'rounded-sm', label: 'Sangat Kecil (2px)' },
                                { id: 'rounded-md', label: 'Sedikit Bulat (4px)' },
                                { id: 'rounded-lg', label: 'Bulat Standar (8px)' },
                                { id: 'rounded-xl', label: 'Cukup Bulat (12px)' },
                                { id: 'rounded-2xl', label: 'Sangat Bulat (16px)' },
                                { id: 'rounded-full', label: 'Bulat Penuh (Oval)' },
                              ].map((opt) => (
                                <button
                                  key={opt.id}
                                  type="button"
                                  onClick={() => {
                                    updateSelectedImage({ borderRadius: opt.id });
                                    setOpenImagePopover(null);
                                  }}
                                  className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between transition-all cursor-pointer ${imageBorderRadius === opt.id ? 'bg-emerald-50 text-emerald-700 font-semibold' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}`}
                                >
                                  <span>{opt.label}</span>
                                  {imageBorderRadius === opt.id && <Check className="h-3 w-3 text-emerald-600 shrink-0" />}
                                </button>
                              ))}
                            </div>
                          ))}
                        </div>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider text-left mt-2 leading-none select-none">Bingkai &amp; Sudut</span>
                      </div>

                      {/* 3. PELETAKAN & EFEK (Arrange & Shadow) */}
                      <div className="flex flex-col justify-between px-2.5 border-b border-slate-200 pb-3 min-w-full h-auto">
                        <div className="flex flex-wrap items-center gap-1.5 h-auto">
                          {renderRibbonDropdown('position', 'Tata Letak', <AlignJustify className="h-4 w-4 text-amber-600 shrink-0" />, (
                            <div className="space-y-1 w-[220px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Aliran Teks (Wrap)</span>
                              {[
                                { id: 'layout-block', label: 'Baris Baru (Tengah)', desc: 'Gambar di tengah, teks terpisah' },
                                { id: 'layout-float-left', label: 'Samping Kiri', desc: 'Gambar di kiri, teks mengalir di kanan' },
                                { id: 'layout-float-right', label: 'Samping Kanan', desc: 'Gambar di kanan, teks mengalir di kiri' },
                                { id: 'layout-inline', label: 'Sejajar Teks (Inline)', desc: 'Menyatu seperti karakter huruf' },
                              ].map((opt) => {
                                const isActive = selectedImageElement.classList.contains(opt.id) || (opt.id === 'layout-block' && selectedImageElement.classList.contains('layout-block') && !selectedImageElement.classList.contains('layout-float-left') && !selectedImageElement.classList.contains('layout-float-right') && !selectedImageElement.classList.contains('layout-inline'));
                                return (
                                  <button
                                    key={opt.id}
                                    type="button"
                                    onClick={() => {
                                      updateSelectedImage({ layout: opt.id as any });
                                      setOpenImagePopover(null);
                                    }}
                                    className={`w-full text-left px-2.5 py-1.5 rounded-lg flex flex-col gap-0.5 transition-all cursor-pointer ${isActive ? 'bg-amber-50 text-amber-700' : 'text-slate-600 hover:bg-slate-50'}`}
                                  >
                                    <span className="text-xs font-bold flex items-center justify-between">
                                      <span>{opt.label}</span>
                                      {isActive && <Check className="h-3 w-3 text-amber-600 shrink-0" />}
                                    </span>
                                    <span className="text-[9px] text-slate-400 font-medium leading-tight">{opt.desc}</span>
                                  </button>
                                );
                              })}
                            </div>
                          ))}

                          {renderRibbonDropdown('rotate', 'Putar & Balik', <RotateCw className="h-4 w-4 text-amber-600 shrink-0" />, (
                            <div className="space-y-1.5 w-[190px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Rotasi &amp; Mirror</span>
                              <button
                                type="button"
                                onClick={() => {
                                  updateSelectedImage({ rotate: (imageRotate + 90) % 360 });
                                }}
                                className="w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg text-slate-600 hover:bg-slate-50 hover:text-slate-950 flex items-center gap-2 cursor-pointer"
                              >
                                <RotateCw className="h-3 w-3 text-amber-500 shrink-0" />
                                <span>Putar Kanan 90°</span>
                              </button>
                              <button
                                type="button"
                                onClick={() => {
                                  updateSelectedImage({ rotate: (imageRotate - 90 + 360) % 360 });
                                }}
                                className="w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg text-slate-600 hover:bg-slate-50 hover:text-slate-950 flex items-center gap-2 cursor-pointer"
                              >
                                <RotateCw className="h-3 w-3 text-amber-500 shrink-0 -scale-x-100" />
                                <span>Putar Kiri 90°</span>
                              </button>

                              <div className="border-t border-slate-100 my-1.5"></div>

                              <button
                                type="button"
                                onClick={() => {
                                  updateSelectedImage({ scaleX: imageScaleX === 1 ? -1 : 1 });
                                }}
                                className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between cursor-pointer ${imageScaleX === -1 ? 'bg-amber-50 text-amber-700' : 'text-slate-600 hover:bg-slate-50'}`}
                              >
                                <div className="flex items-center gap-2">
                                  <FlipHorizontal className="h-3.5 w-3.5 text-amber-600" />
                                  <span>Balik Horisontal</span>
                                </div>
                                {imageScaleX === -1 && <Check className="h-3 w-3 text-amber-600" />}
                              </button>
                              <button
                                type="button"
                                onClick={() => {
                                  updateSelectedImage({ scaleY: imageScaleY === 1 ? -1 : 1 });
                                }}
                                className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between cursor-pointer ${imageScaleY === -1 ? 'bg-amber-50 text-amber-700' : 'text-slate-600 hover:bg-slate-50'}`}
                              >
                                <div className="flex items-center gap-2">
                                  <FlipVertical className="h-3.5 w-3.5 text-amber-600" />
                                  <span>Balik Vertikal</span>
                                </div>
                                {imageScaleY === -1 && <Check className="h-3 w-3 text-amber-600" />}
                              </button>
                            </div>
                          ))}

                          {renderRibbonDropdown('shadow', 'Efek Bayangan', <Sparkles className="h-4 w-4 text-amber-600 shrink-0" />, (
                            <div className="space-y-1 w-[180px]">
                              <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider px-1 mb-1">Gaya Bayangan (Elevation)</span>
                              {[
                                { id: 'none', label: 'Tanpa Bayangan' },
                                { id: 'shadow-xs', label: 'Sangat Tipis (XS)' },
                                { id: 'shadow-sm', label: 'Tipis (SM)' },
                                { id: 'shadow-md', label: 'Sedang (MD)' },
                                { id: 'shadow-lg', label: 'Besar (LG)' },
                                { id: 'shadow-xl', label: 'Sangat Besar (XL)' },
                                { id: 'shadow-2xl', label: 'Sangat Tebal (2XL)' },
                                { id: 'shadow-inner', label: 'Bayangan Dalam' },
                              ].map((opt) => (
                                <button
                                  key={opt.id}
                                  type="button"
                                  onClick={() => {
                                    updateSelectedImage({ shadow: opt.id });
                                    setOpenImagePopover(null);
                                  }}
                                  className={`w-full text-left px-2.5 py-1.5 text-xs font-medium rounded-lg flex items-center justify-between transition-all cursor-pointer ${imageShadow === opt.id ? 'bg-amber-50 text-amber-700 font-semibold' : 'text-slate-600 hover:bg-slate-50 hover:text-slate-900'}`}
                                >
                                  <span>{opt.label}</span>
                                  {imageShadow === opt.id && <Check className="h-3 w-3 text-amber-600 shrink-0" />}
                                </button>
                              ))}
                            </div>
                          ))}
                        </div>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider text-left mt-2 leading-none select-none">Peletakan &amp; Efek</span>
                      </div>

                      {/* 4. UKURAN & PROPORSI (Size & Aspect) */}
                      <div className="flex flex-col justify-between px-2.5 border-b border-slate-200 pb-3 min-w-full h-auto">
                        <div className="flex flex-wrap items-center gap-1.5 h-auto">
                          {renderRibbonDropdown('size', 'Ukuran', <Maximize2 className="h-4 w-4 text-purple-600 shrink-0" />, (
                            <div className="space-y-3 w-[210px] p-1">
                              <div>
                                <span className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1.5">Preset Lebar</span>
                                <div className="grid grid-cols-4 gap-1">
                                  {['25%', '50%', '75%', '100%'].map((pct) => (
                                    <button
                                      key={pct}
                                      type="button"
                                      onClick={() => {
                                        updateSelectedImage({ width: pct });
                                      }}
                                      className={`py-1 text-xs font-semibold rounded-lg border cursor-pointer transition-all ${imageWidth === pct ? 'bg-purple-600 border-purple-600 text-white shadow-xs' : 'bg-slate-50 border-slate-200 text-slate-600 hover:bg-slate-100'}`}
                                    >
                                      {pct}
                                    </button>
                                  ))}
                                </div>
                              </div>
                              <div className="border-t border-slate-100 pt-2.5">
                                <div className="flex justify-between items-center text-xs mb-1.5">
                                  <span className="font-semibold text-slate-600">Presisi Lebar</span>
                                  <span className="font-bold text-purple-600 font-mono">{imageWidth}</span>
                                </div>
                                <input
                                  type="range"
                                  min="10"
                                  max="100"
                                  value={parseInt(imageWidth) || 60}
                                  onChange={(e) => updateSelectedImage({ width: `${e.target.value}%` })}
                                  className="w-full accent-purple-600 h-1 cursor-pointer bg-slate-200 rounded-lg appearance-none"
                                />
                              </div>
                            </div>
                          ))}

                          {/* Height Precision Input */}
                          <div className="flex items-center bg-white border border-slate-200 rounded-lg px-2 h-7 gap-1">
